head.b:skin:
/* MYTEN.IN – LIVE ENGINE 2026
   Fixes: Clickability, new posts visibility, grid layout
*/
:root {
  --accent: #e1a66c;
  --dark: #111827;
  --gray: #6b7280;
  --border: #f3f4f6;
}

*, *::before, *::after { box-sizing: border-box; }
body {
  background: #fafafa;
  color: var(--dark);
  font-family: 'Inter', -apple-system, sans-serif;
  margin: 0;
}

header {
  background: #fff;
  padding: 16px 20px;
  border-bottom: 1px solid var(--border);
  position: sticky;
  top: 0;
  z-index: 100;
  -webkit-backdrop-filter: blur(12px);
  backdrop-filter: blur(12px);
}

.nav-container {
  max-width: 1100px;
  margin: 0 auto;
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap;
  gap: 12px;
}

.logo {
  font-family: 'Plus Jakarta Sans', sans-serif;
  font-weight: 800;
  font-size: 24px;
  color: var(--dark);
  text-decoration: none;
  letter-spacing: -1px;
}

.search-wrapper { display: flex; align-items: center; }
.search-container {
  display: flex;
  align-items: center;
  background: #f3f4f6;
  border-radius: 50px;
  padding: 6px 14px;
  border: 1px solid transparent;
  transition: all 0.2s ease;
}
.search-container:focus-within {
  background: #fff;
  border-color: var(--accent);
  box-shadow: 0 0 0 3px rgba(225,166,108,0.12);
}
.search-input {
  background: transparent;
  border: none;
  outline: none;
  padding: 6px 8px;
  font-size: 14px;
  width: 160px;
  transition: width 0.2s ease;
}
.search-input:focus { width: 220px; }
.search-button {
  background: none;
  border: none;
  cursor: pointer;
  color: var(--gray);
  padding: 4px;
  display: flex;
  align-items: center;
  justify-content: center;
}
.search-button svg { width: 18px; height: 18px; }
@media (max-width: 600px) {
  .search-input { width: 100px; }
  .search-input:focus { width: 140px; }
}

.feed-wrapper {
  max-width: 1100px;
  margin: 32px auto;
  padding: 0 20px;
}

.post-outer-container {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: 24px;
}

.item-post {
  background: #fff;
  border-radius: 12px;
  border: 1px solid var(--border);
  overflow: hidden;
  transition: transform 0.2s ease, box-shadow 0.2s ease;
  position: relative;
  display: flex;
  flex-direction: column;
}

.item-post:hover {
  transform: translateY(-5px);
  box-shadow: 0 12px 28px rgba(0,0,0,0.06);
}

.item-post a.main-url {
  position: absolute;
  top: 0; left: 0; width: 100%; height: 100%;
  z-index: 5;
  text-indent: -9999px;
}

.post-thumb {
  width: 100%;
  height: 200px;
  background: #eee;
  object-fit: cover;
  display: block;
}

.post-thumb-placeholder {
  width: 100%;
  height: 200px;
  background: linear-gradient(135deg, #f3f4f6 0%, #e5e7eb 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--gray);
  font-size: 14px;
  font-family: 'Plus Jakarta Sans', sans-serif;
}

.post-info { padding: 20px; }
.post-info h2 {
  font-family: 'Plus Jakarta Sans', sans-serif;
  font-size: 18px;
  font-weight: 600;
  margin: 0 0 10px;
  line-height: 1.4;
  color: var(--dark);
}
.post-info p {
  font-size: 14px;
  color: var(--gray);
  margin: 0;
  line-height: 1.5;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.blog-pager-wrap {
  margin-top: 36px;
  text-align: center;
}
.blog-pager-wrap a {
  display: inline-block;
  padding: 10px 22px;
  background: #fff;
  border: 1px solid var(--border);
  border-radius: 8px;
  color: var(--dark);
  text-decoration: none;
  font-weight: 500;
  transition: all 0.2s;
}
.blog-pager-wrap a:hover {
  border-color: var(--accent);
  color: var(--accent);
}

.post-body { font-size: 16px; line-height: 1.75; }
